// Parse Stratum job notification from pool
struct StratumJob {
    std::string job_id;
    std::string blob;       // block template (hex)
    std::string target;     // difficulty target (hex)
    bool        clean_jobs;
    bool        valid = false;
};

StratumJob ParseStratumNotify(const std::string& json_line) {
    StratumJob job;
    // Minimal JSON parse for mining.notify
    // Format: {"method":"mining.notify","params":["jobid","blob","target",true]}
    auto find_str = [&](const std::string& key) -> std::string {
        size_t kp = json_line.find(key);
        if (kp == std::string::npos) return "";
        size_t q1 = json_line.find('"', kp + key.size());
        if (q1 == std::string::npos) return "";
        size_t q2 = json_line.find('"', q1 + 1);
        if (q2 == std::string::npos) return "";
        return json_line.substr(q1 + 1, q2 - q1 - 1);
    };

    if (json_line.find("mining.notify") == std::string::npos) return job;

    // Extract params array elements
    size_t params = json_line.find("\"params\"");
    if (params == std::string::npos) return job;
    size_t bracket = json_line.find('[', params);
    if (bracket == std::string::npos) return job;

    // Parse quoted strings in order: job_id, blob, target
    size_t pos = bracket;
    std::vector<std::string> fields;
    while (fields.size() < 3) {
        size_t q1 = json_line.find('"', pos + 1);
        if (q1 == std::string::npos) break;
        size_t q2 = json_line.find('"', q1 + 1);
        if (q2 == std::string::npos) break;
        fields.push_back(json_line.substr(q1 + 1, q2 - q1 - 1));
        pos = q2 + 1;
    }

    if (fields.size() >= 3) {
        job.job_id  = fields[0];
        job.blob    = fields[1];
        job.target  = fields[2];
        job.valid   = true;
        // clean_jobs: look for true/false after last quoted field
        job.clean_jobs = (json_line.find("true", pos) != std::string::npos);
    }
    return job;
}

